    79	
    80	// cbcEncrypt adds PKCS5 padding and encrypts plaintext in CBC mode.
    81	func cbcEncrypt(block cipher.Block, iv, plaintext []byte) ([]byte, error) {
    82		if len(iv) != block.BlockSize() {
    83			return nil, errInvalidIVLength
    84		}
    85	
    86		padded := pkcs5Padding(plaintext, block.BlockSize())
    87		dst := make([]byte, len(padded))
    88		cipher.NewCBCEncrypter(block, iv).CryptBlocks(dst, padded)
    89		return dst, nil
    90	}
    91	
    92	// cbcDecrypt decrypts ciphertext in CBC mode and removes PKCS5 padding.
    93	func cbcDecrypt(block cipher.Block, iv, ciphertext []byte) ([]byte, error) {
    94		bs := block.BlockSize()
    95		if len(iv) != bs {
    96			return nil, errInvalidIVLength
    97		}
    98		if len(ciphertext) < bs {
    99			return nil, errShortCiphertext
   100		}
   101		if len(ciphertext)%bs != 0 {
   102			return nil, errInvalidBlockSize
   103		}
   104	
   105		dst := make([]byte, len(ciphertext))
   106		cipher.NewCBCDecrypter(block, iv).CryptBlocks(dst, ciphertext)
   107	
   108		dst, err := pkcs5UnPadding(dst, bs)
   109		if err != nil {
   110			return nil, fmt.Errorf("decrypt: %w", err)
   111		}
   112		return dst, nil
   113	}
   114	
   115	// paddingZero pads src with zero bytes to the given length.
   116	// Returns src unchanged if already long enough; otherwise returns a new slice.
   117	func paddingZero(src []byte, length int) []byte {
   118		if len(src) >= length {
   119			return src
   120		}
   121		dst := make([]byte, length)
   122		copy(dst, src)
   123		return dst
   124	}
   125	
   126	// pkcs5Padding adds PKCS5/PKCS7 padding to src.
   127	// Always returns a new slice; never modifies src.
   128	func pkcs5Padding(src []byte, blockSize int) []byte {
   129		n := blockSize - (len(src) % blockSize)
   130		dst := make([]byte, len(src)+n)
   131		copy(dst, src)
   132		for i := len(src); i < len(dst); i++ {
   133			dst[i] = byte(n)
   134		}
   135		return dst
   136	}
   137	
   138	// pkcs5UnPadding removes PKCS5/PKCS7 padding from src.
   139	func pkcs5UnPadding(src []byte, blockSize int) ([]byte, error) {
   140		length := len(src)
   141		if length == 0 {
   142			return nil, errInvalidPadding
   143		}
   144		padding := int(src[length-1])
   145		if padding < 1 || padding > blockSize || padding > length {
   146			return nil, errInvalidPadding
   147		}
   148		for _, b := range src[length-padding:] {
   149			if int(b) != padding {
   150				return nil, errInvalidPadding
   151			}
   152		}
   153		return src[:length-padding], nil
   154	}
