     1	package chromium
     2	
     3	import (
     4		"fmt"
     5		"os"
     6		"path/filepath"
     7		"time"
     8	
     9		"github.com/moond4rk/hackbrowserdata/crypto/keyretriever"
    10		"github.com/moond4rk/hackbrowserdata/filemanager"
    11		"github.com/moond4rk/hackbrowserdata/log"
    12		"github.com/moond4rk/hackbrowserdata/types"
    13		"github.com/moond4rk/hackbrowserdata/utils/fileutil"
    14	)
    15	
    16	// Browser represents a single Chromium profile ready for extraction.
    17	type Browser struct {
    18		cfg         types.BrowserConfig
    19		profileDir  string                               // absolute path to profile directory
    20		retriever   keyretriever.KeyRetriever            // set via SetRetriever after construction
    21		sources     map[types.Category][]sourcePath      // Category → candidate paths (priority order)
    22		extractors  map[types.Category]categoryExtractor // Category → custom extract function override
    23		sourcePaths map[types.Category]resolvedPath      // Category → discovered absolute path
    24	}
    25	
    26	// NewBrowsers discovers Chromium profiles under cfg.UserDataDir and returns
    27	// one Browser per profile. Call SetRetriever on each returned browser before
    28	// Extract to enable decryption of sensitive data (passwords, cookies, etc.).
    29	func NewBrowsers(cfg types.BrowserConfig) ([]*Browser, error) {
    30		sources := sourcesForKind(cfg.Kind)
    31		extractors := extractorsForKind(cfg.Kind)
    32	
    33		profileDirs := discoverProfiles(cfg.UserDataDir, sources)
    34		if len(profileDirs) == 0 {
    35			return nil, nil
    36		}
    37	
    38		var browsers []*Browser
    39		for _, profileDir := range profileDirs {
    40			sourcePaths := resolveSourcePaths(sources, profileDir)
    41			if len(sourcePaths) == 0 {
    42				continue
    43			}
    44			browsers = append(browsers, &Browser{
    45				cfg:         cfg,
    46				profileDir:  profileDir,
    47				sources:     sources,
    48				extractors:  extractors,
    49				sourcePaths: sourcePaths,
    50			})
    51		}
    52		return browsers, nil
    53	}
    54	
    55	// SetRetriever sets the key retriever used by Extract to obtain the
    56	// master encryption key. Must be called before Extract if encrypted
    57	// data (passwords, cookies, credit cards) needs to be decrypted.
    58	func (b *Browser) SetRetriever(r keyretriever.KeyRetriever) {
    59		b.retriever = r
    60	}
    61	
    62	func (b *Browser) BrowserName() string { return b.cfg.Name }
    63	func (b *Browser) ProfileDir() string  { return b.profileDir }
    64	func (b *Browser) ProfileName() string {
    65		if b.profileDir == "" {
    66			return ""
    67		}
    68		return filepath.Base(b.profileDir)
    69	}
    70	
    71	// Extract copies browser files to a temp directory, retrieves the master key,
    72	// and extracts data for the requested categories.
    73	func (b *Browser) Extract(categories []types.Category) (*types.BrowserData, error) {
    74		session, err := filemanager.NewSession()
    75		if err != nil {
    76			return nil, err
    77		}
    78		defer session.Cleanup()
    79	
    80		tempPaths := b.acquireFiles(session, categories)
    81	
    82		masterKey, err := b.getMasterKey(session)
    83		if err != nil {
    84			log.Debugf("get master key for %s: %v", b.BrowserName()+"/"+b.ProfileName(), err)
    85		}
    86	
    87		data := &types.BrowserData{}
    88		for _, cat := range categories {
    89			path, ok := tempPaths[cat]
    90			if !ok {
    91				continue
    92			}
    93			b.extractCategory(data, cat, masterKey, path)
    94		}
    95		return data, nil
    96	}
    97	
    98	// CountEntries copies browser files to a temp directory and counts entries
    99	// per category without decryption. Much faster than Extract for display-only
   100	// use cases like "list --detail".
   101	func (b *Browser) CountEntries(categories []types.Category) (map[types.Category]int, error) {
   102		session, err := filemanager.NewSession()
   103		if err != nil {
   104			return nil, err
   105		}
   106		defer session.Cleanup()
   107	
   108		tempPaths := b.acquireFiles(session, categories)
   109	
   110		counts := make(map[types.Category]int)
   111		for _, cat := range categories {
   112			path, ok := tempPaths[cat]
   113			if !ok {
   114				continue
   115			}
   116			counts[cat] = b.countCategory(cat, path)
   117		}
   118		return counts, nil
   119	}
   120	
   121	// countCategory calls the appropriate count function for a category.
   122	func (b *Browser) countCategory(cat types.Category, path string) int {
   123		var count int
   124		var err error
   125		switch cat {
   126		case types.Password:
   127			count, err = countPasswords(path)
   128		case types.Cookie:
   129			count, err = countCookies(path)
   130		case types.History:
   131			count, err = countHistories(path)
   132		case types.Download:
   133			count, err = countDownloads(path)
   134		case types.Bookmark:
   135			count, err = countBookmarks(path)
   136		case types.CreditCard:
   137			count, err = countCreditCards(path)
   138		case types.Extension:
   139			if b.cfg.Kind == types.ChromiumOpera {
   140				count, err = countOperaExtensions(path)
   141			} else {
   142				count, err = countExtensions(path)
   143			}
   144		case types.LocalStorage:
   145			count, err = countLocalStorage(path)
   146		case types.SessionStorage:
   147			count, err = countSessionStorage(path)
   148		}
   149		if err != nil {
   150			log.Debugf("count %s for %s: %v", cat, b.BrowserName()+"/"+b.ProfileName(), err)
   151		}
   152		return count
   153	}
   154	
   155	// acquireFiles copies source files to the session temp directory.
   156	func (b *Browser) acquireFiles(session *filemanager.Session, categories []types.Category) map[types.Category]string {
   157		tempPaths := make(map[types.Category]string)
   158		for _, cat := range categories {
   159			rp, ok := b.sourcePaths[cat]
   160			if !ok {
   161				continue
   162			}
   163			dst := filepath.Join(session.TempDir(), cat.String())
   164			if err := session.Acquire(rp.absPath, dst, rp.isDir); err != nil {
   165				log.Debugf("acquire %s: %v", cat, err)
   166				continue
   167			}
   168			tempPaths[cat] = dst
   169		}
   170		return tempPaths
   171	}
   172	
   173	// getMasterKey retrieves the Chromium master encryption key.
   174	//
   175	// On Windows, the key is read from the Local State file and decrypted via DPAPI.
   176	// On macOS, the key is derived from Keychain (Local State is not needed).
   177	// On Linux, the key is derived from D-Bus Secret Service or a fallback password.
   178	//
   179	// The retriever is always called regardless of whether Local State exists,
   180	// because macOS/Linux retrievers don't need it.
   181	func (b *Browser) getMasterKey(session *filemanager.Session) ([]byte, error) {
   182		if b.retriever == nil {
   183			return nil, fmt.Errorf("key retriever not set for %s", b.cfg.Name)
   184		}
   185	
   186		// Try to locate and copy Local State (needed on Windows, ignored on macOS/Linux).
   187		// Multi-profile layout: Local State is in the parent of profileDir.
   188		// Flat layout (Opera): Local State is alongside data files in profileDir.
   189		var localStateDst string
   190		for _, dir := range []string{filepath.Dir(b.profileDir), b.profileDir} {
   191			candidate := filepath.Join(dir, "Local State")
   192			if fileutil.FileExists(candidate) {
   193				localStateDst = filepath.Join(session.TempDir(), "Local State")
   194				if err := session.Acquire(candidate, localStateDst, false); err != nil {
   195					return nil, err
   196				}
   197				break
   198			}
   199		}
   200	
   201		return b.retriever.RetrieveKey(b.cfg.Storage, localStateDst)
   202	}
   203	
   204	// extractCategory calls the appropriate extract function for a category.
   205	// If a custom extractor is registered for this category (via extractorsForKind),
   206	// it is used instead of the default switch logic.
   207	func (b *Browser) extractCategory(data *types.BrowserData, cat types.Category, masterKey []byte, path string) {
   208		if ext, ok := b.extractors[cat]; ok {
   209			if err := ext.extract(masterKey, path, data); err != nil {
   210				log.Debugf("extract %s for %s: %v", cat, b.BrowserName()+"/"+b.ProfileName(), err)
   211			}
   212			return
   213		}
   214	
   215		var err error
   216		switch cat {
   217		case types.Password:
   218			data.Passwords, err = extractPasswords(masterKey, path)
   219		case types.Cookie:
   220			data.Cookies, err = extractCookies(masterKey, path)
   221		case types.History:
   222			data.Histories, err = extractHistories(path)
   223		case types.Download:
   224			data.Downloads, err = extractDownloads(path)
   225		case types.Bookmark:
   226			data.Bookmarks, err = extractBookmarks(path)
   227		case types.CreditCard:
   228			data.CreditCards, err = extractCreditCards(masterKey, path)
   229		case types.Extension:
   230			data.Extensions, err = extractExtensions(path)
   231		case types.LocalStorage:
   232			data.LocalStorage, err = extractLocalStorage(path)
   233		case types.SessionStorage:
   234			data.SessionStorage, err = extractSessionStorage(path)
   235		}
   236		if err != nil {
   237			log.Debugf("extract %s for %s: %v", cat, b.BrowserName()+"/"+b.ProfileName(), err)
   238		}
   239	}
   240	
   241	// discoverProfiles lists subdirectories of userDataDir that are valid
   242	// Chromium profile directories. A directory is considered a profile if it
   243	// contains a "Preferences" file, which Chromium creates for every profile.
   244	func discoverProfiles(userDataDir string, sources map[types.Category][]sourcePath) []string {
   245		entries, err := os.ReadDir(userDataDir)
   246		if err != nil {
   247			return nil
   248		}
   249	
   250		var profiles []string
   251		for _, e := range entries {
   252			if !e.IsDir() || isSkippedDir(e.Name()) {
   253				continue
   254			}
   255			dir := filepath.Join(userDataDir, e.Name())
   256			if isProfileDir(dir) {
   257				profiles = append(profiles, dir)
   258			}
   259		}
