cat > /tmp/repro_v11_linux.go <<'EOF'
package main

import (
	"bytes"
	"fmt"
	"os"

	hbdcrypto "github.com/moond4rk/hackbrowserdata/crypto"
)

func decryptLikeChromium(masterKey, ciphertext []byte) ([]byte, error) {
	version := hbdcrypto.DetectVersion(ciphertext)
	switch string(version) {
	case "v10", "v11":
		return hbdcrypto.DecryptChromium(masterKey, ciphertext)
	case "v20":
		return nil, fmt.Errorf("v20 App-Bound Encryption not yet supported")
	case "dpapi":
		return hbdcrypto.DecryptDPAPI(ciphertext)
	default:
		return nil, fmt.Errorf("unsupported cipher version: %s", version)
	}
}

func main() {
	key := []byte("0123456789abcdef")
	plaintext := []byte("decoded-cookie")
	iv := bytes.Repeat([]byte{0x20}, 16)
	payload, err := hbdcrypto.AESCBCEncrypt(key, iv, plaintext)
	if err != nil {
		fmt.Println("encrypt:", err)
		os.Exit(2)
	}
	ciphertext := append([]byte("v11"), payload...)
	got, err := decryptLikeChromium(key, ciphertext)
